<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <i-page-title title="fileUpload" />
      <v-col cols="12" sm="12" lg="12" class="pa-2">
        <i-card-vertical headerTitle="파일업로드" :useBtnList="buttonUseList" @btnSearch="btnSearch()" @btnAdd="btnAdd()">
          <template v-slot:body>
            <v-layout column layout-col-height5 overflow-auto>
              <v-col cols="12" md="12" class="row pa-0">
                <v-col cols="12" lg="12" class="mt-2">
                  <DxDataGrid
                    id="targetDataGrid"
                    class="layout-col-height5-body"
                    :ref="dxDataGridRef"
                    :data-source="files"
                    :remote-operations="false"
                    :hover-state-enabled="true"
                    :allow-column-resizing="true"
                    :allow-column-reordering="true"
                    :row-alternation-enabled="true"
                    :column-auto-width="true"
                    :show-borders="true"
                    :show-row-lines="true"
                    key="id"
                  >
                    <DxSelection :select-all-mode="allMode" show-check-boxes-mode="always" mode="multiple" />

                    <DxEditing mode="batch" :allow-adding="true" :allow-updating="true" />

                    <DxColumn
                      data-field="fileId"
                      caption="파일아이디"
                      width="200px"
                      data-type="string"
                      alignment="center"
                      css-class="devest-grid-header-require"
                    />

                    <DxColumn
                      data-field="fileNm"
                      caption="파일이름"
                      width="200px"
                      data-type="string"
                      alignment="center"
                      css-class="devest-grid-header-require"
                    />

                    <DxColumn data-field="createdAt" data-type="string" caption="파일등록일자" width="200px" alignment="center" />

                    <DxColumn data-field="createdBy" data-type="string" caption="파일등록자" width="200px" alignment="center" />

                    <DxColumn data-field="fileDesc" caption="비고" data-type="string" alignment="center" />

                    <template #checkBoxEditor="{ data: cellInfo }">
                      <DxCheckBox :value="cellInfo.value == 'Y' ? true : false" :onValueChanged="value => onCheckValueChanged(value, cellInfo)" />
                    </template>
                  </DxDataGrid>
                </v-col>
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { DxDataGrid, DxColumn, DxSelection, DxEditing } from 'devextreme-vue/data-grid'
import iPageTitle from '@/components/common/iPageTitle.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import { DxFileUploader } from 'devextreme-vue/file-uploader'
import { getFile, getFileList, deleteFile, download, getTargetList } from '@/api/baseManage/fileUpload'
import notify from 'devextreme/ui/notify'
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가
  name: 'groupManage',
  components: {
    DxDataGrid,
    DxColumn,
    DxFileUploader,
    DxEditing,
    DxSelection,
    'i-page-title': iPageTitle,
    'i-card-vertical': iCardVertical
  },
  data() {
    return {
      dxDataGridRef: 'targetDataGrid',
      dxFileDataGridRef: 'fileDataGrid',
      dxFileUploader: 'uploaderContainer',
      allowedFileExtensions: ['.jpg', '.jpeg', '.gif', '.png'],
      fileData: [],
      uploadermultiData: {},
      files: [],
      allMode: 'allPages',
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd'
      ],
      selectTargetType: [
        { minorCd: 'Report', minorNm: 'Report' },
        { minorCd: 'User_Pic', minorNm: 'User_Pic' }
      ],

      selectTargetId: [
        { minorCd: 'test', minorNm: 'test' },
        { minorCd: 'test1', minorNm: 'test1' }
      ],
      selectedTargetType: '',
      selectedTargetId: '',
      targetList: [],
      searchParams: {}
    }
  },
  computed: {
    gridData: function() {
      return this.$refs[this.dxDataGridRef].instance
    },
    fileUploader: function() {
      return this.$refs[this.dxFileUploader].instance
    },
    fileGridData: function() {
      return this.$refs[this.dxFileDataGridRef].instance
    }
  },
  beforeMount() {
    getTargetList().then(res => {
      this.targetList = []
      this.targetList = res.list
    })
  },
  methods: {
    ///////////////////////////////////////
    /*       File Uploader Event        */
    ///////////////////////////////////////
    onUploaded(e) {
      e.component._files.forEach((element, index) => {
        if (element._isLoaded) {
          this.fileUploader.removeFile(index)
        }
      })
      notify(this.$t('파일이 업로드 되었습니다.'), 'success', 300)
    },
    onUploadError(e) {
      e.component._files.forEach((element, index) => {
        if (element._isError) {
          this.fileUploader.removeFile(index)
        }
      })
      notify(this.$t('파일이 업로드에 실패하였습니다.'), 'error', 300)
    },
    onStartedUpload() {},
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    btnSearch() {
      this.vToastifyPrompt(
        this.$t('test'),
        'question',
        current => {
          console.log('yes')
        },
        res => {
          console.log('no')
        },
        true
      )
    },
    btnAdd() {
      let newRow = {
        id: this.files.length + 1
      }
      console.log(this.gridData)
      this.gridData.addRow(newRow)
      this.gridData.saveEditData()
    },
    fileRemove(file) {
      this.$vToastify
        .prompt({
          body: this.$t('doDeleteData'),
          answers: { Yes: true, No: false }
        })
        .then(value => {
          if (!value) return
          else {
            deleteFile([file])
              .then(res => {
                if (res.success) {
                  this.btnSearch()
                  notify(this.$t('파일이 삭제되었습니다.'), 'success', 300)
                }
              })
              .catch(error => {
                if (error.response.data.code == null) {
                  this.$vToastify.error({ body: this.$t('errorToastMsg') + ': ' + this.$t('errorToastServerClose') })
                } else {
                  console.log(error)
                  this.$vToastify.error({
                    body:
                      this.$t('errorToastID') +
                      ': ' +
                      this.$t(error.response.data.code) +
                      '<br>' +
                      this.$t('errorToastMsg') +
                      ': ' +
                      this.$t(error.response.data.msg)
                  })
                }
              })
              .finally(() => {})
          }
        })
    },
    fileSearch() {
      console.log(this.selectTargetType)

      console.log(this.searchParams)

      getFile(this.searchParams)
        .then(res => {
          console.log(res)
          if (res.success) {
            this.files = []
            this.files = res.list
          }
        })
        .catch(error => {
          console.log(error)
          if (error.response.data.code == null) {
            this.$vToastify.error({ body: this.$t('errorToastMsg') + ': ' + this.$t('errorToastServerClose') })
          } else {
            console.log(error)
            this.$vToastify.error({
              body:
                this.$t('errorToastID') +
                ': ' +
                this.$t(error.response.data.code) +
                '<br>' +
                this.$t('errorToastMsg') +
                ': ' +
                this.$t(error.response.data.msg)
            })
          }
        })
        .finally(() => {})
    },
    ///////////////////////////////////////
    /*           DataGrid Event          */
    ///////////////////////////////////////
    onFocusedRowChanged(e) {
      if (e.rowIndex < 0) return

      this.uploadermultiData = { targetType: e.row.values[1], targetId: e.row.values[0] }

      this.searchParams = {
        targetType: e.row.values[1],
        targetId: e.row.values[0],
        fileId: 0
      }

      getFile(this.searchParams)
        .then(res => {
          console.log(res)
          if (res.success) {
            this.files = []
            this.files = res.list
          }
        })
        .catch(error => {
          console.log(error)
          if (error.response.data.code == null) {
            this.$vToastify.error({ body: this.$t('errorToastMsg') + ': ' + this.$t('errorToastServerClose') })
          } else {
            console.log(error)
            this.$vToastify.error({
              body:
                this.$t('errorToastID') +
                ': ' +
                this.$t(error.response.data.code) +
                '<br>' +
                this.$t('errorToastMsg') +
                ': ' +
                this.$t(error.response.data.msg)
            })
          }
        })
        .finally(() => {})
    },
    removeFocus() {
      this.uploadermultiData = { targetType: '', targetId: '' }
      this.gridData.clearSelection()
      this.gridData.option('focusedRowIndex', -1)
    },
    gridInit() {
      this.gridData.clearSelection()
    }
  }
}
</script>

<style>
.widget-container {
  margin-right: 320px;
}

.contents h4 {
  margin-bottom: 10px;
  font-weight: 500;
  font-size: 18px;
}

.contents {
  margin-top: 50px;
  margin-left: 10px;
  display: none;
}

.fileList {
  padding: 10px;
  width: 400px;
  background-color: rgba(183, 183, 183, 0.1);
}

.fileNm {
  height: 20px;
  font-weight: bold;
}

.fileList > .fileSize {
  height: 20px;
  font-size: 12px;
}
</style>
